class Iterator {
  constructor(items) {
    this.index = 0;
    this.items = items;
  }
  first() {
    this.index = 0;
    return this.items[0];
  }
  next() {
    this.index++;
    return this.items[this.index];
  }
  hasNext() {
    return this.items.length - 1 > this.index;
  }
  reset() {
    this.index = 0;
  }
  each(callback) {
    for (let i = 0; i < this.items.length; i++) {
      callback(this.items[i]);
    }
  }
}


