        border-radius: 8px;
        cursor: pointer;
      }
      .btn:hover,
      select:hover {
        border-color: var(--baseline);
      }
      .live {
        font-size: 12px;
        color: var(--muted);
        margin-left: auto;
      }

      /* ── 카드 ── */
      .card {
        background: var(--surface);
        border: 1px solid var(--border);
        border-radius: 12px;
        padding: 16px 18px;
      }
      .card-head {
        display: flex;
        align-items: baseline;
        gap: 10px;
        margin-bottom: 4px;
      }
      .card-title {
        font-size: 14px;
        font-weight: 600;
        margin: 0;
      }
      .card-sub {
        font-size: 12px;
        color: var(--muted);
        margin: 0;
      }
      .card-head .btn {
        margin-left: auto;
        padding: 3px 9px;
        font-size: 11px;
        border-radius: 6px;
      }

      .grid {
        display: grid;
        gap: 16px;
        margin-bottom: 16px;
      }
      .g-kpi {
        grid-template-columns: repeat(auto-fit, minmax(170px, 1fr));
      }
      .g-two {
        grid-template-columns: repeat(auto-fit, minmax(420px, 1fr));
      }

      /* ── 스탯 타일 ── */
      .tile .label {
        font-size: 12px;
        color: var(--ink-2);
      }
      .tile .value {
        font-size: 28px;
        font-weight: 600;
        margin-top: 2px;
        letter-spacing: -0.01em;
      }
      .tile .foot {
        font-size: 12px;
        color: var(--muted);
        margin-top: 2px;
      }

      /* ── 상태 칩 (아이콘 + 라벨 + 색: 색 단독으로 의미를 전달하지 않음) ── */
      .chips {
        display: flex;
        flex-wrap: wrap;
        gap: 8px;
        margin-top: 10px;
      }
      .chip {
        display: inline-flex;
        align-items: center;
        gap: 6px;
        padding: 5px 11px 5px 9px;
        border: 1px solid var(--border);
        border-radius: 999px;
        font-size: 12px;
        color: var(--ink-2);
        background: var(--surface);
      }
      .chip .ico {
        font-size: 11px;
        font-weight: 700;
        line-height: 1;
      }
      .chip .nm {
        color: var(--ink);
        font-weight: 500;
      }

      /* ── 표 보기 ── */
      table {
        width: 100%;
        border-collapse: collapse;
        font-size: 12.5px;
        margin-top: 10px;
      }
      th,
      td {
        text-align: right;
        padding: 5px 8px;
        border-bottom: 1px solid var(--grid);
        font-variant-numeric: tabular-nums;
      }
      th:first-child,
      td:first-child {
        text-align: left;
        font-variant-numeric: normal;
      }
      th {
        color: var(--muted);
        font-weight: 500;
      }
      .tablewrap {
        max-height: 240px;
        overflow: auto;
      }
      .hidden {
        display: none;
      }

      /* ── 범례 ── */
      .legend {
        display: flex;
        gap: 16px;
        margin-top: 2px;
      }
      .legend .key {
        display: inline-flex;
        align-items: center;
        gap: 6px;
        font-size: 12px;
        color: var(--ink-2);
      }
      .legend .swatch-line {
        width: 14px;
        height: 2px;
        border-radius: 1px;
      }

      /* ── 툴팁 ── */
      .tip {
        position: fixed;
        pointer-events: none;
        z-index: 10;
        min-width: 130px;
        padding: 8px 10px;
        background: var(--surface);
        border: 1px solid var(--border);
        border-radius: 8px;
        box-shadow: 0 4px 16px rgba(0, 0, 0, 0.14);
        font-size: 12px;
        opacity: 0;
        transition: opacity 0.1s;
      }
      .tip.on {
        opacity: 1;
      }
      .tip .t-head {
        color: var(--muted);
        margin-bottom: 5px;
        font-variant-numeric: tabular-nums;
      }
      .tip .t-row {
        display: flex;
        align-items: center;
        gap: 6px;
        margin-top: 3px;
      }
      .tip .t-key {
        width: 12px;
        height: 2px;
        border-radius: 1px;
        flex: none;
      }
      .tip .t-name {
        color: var(--ink-2);
      }
      .tip .t-val {
        margin-left: auto;
        font-weight: 600;
        color: var(--ink);
        font-variant-numeric: tabular-nums;
      }

      svg {
        display: block;
        width: 100%;
      }
      svg text {
        font-family:
          system-ui,
          -apple-system,
          "Segoe UI",
          sans-serif;
      }

      details.raw {
        margin-top: 16px;
      }
      details.raw summary {
        cursor: pointer;
        font-size: 13px;
        color: var(--ink-2);
        padding: 6px 0;
      }
      .raw-grid {
        display: grid;
        grid-template-columns: 260px 1fr;
        gap: 16px;
        margin-top: 10px;
      }
      .ep {
        display: block;
        width: 100%;
        padding: 9px 12px;
        border: 0;
        border-bottom: 1px solid var(--grid);
        background: transparent;
        color: var(--ink);
        text-align: left;
        cursor: pointer;
        font: inherit;
        font-size: 13px;
      }
      .ep:last-child {
        border-bottom: 0;
      }
      .ep:hover {
        background: var(--page);
      }
      .ep .p {
        font-family: ui-monospace, Menlo, monospace;
        font-size: 12.5px;
      }
      .ep .d {
        font-size: 11.5px;
        color: var(--muted);
      }
      pre {
        margin: 0;
        padding: 12px;
        max-height: 380px;
        overflow: auto;
        background: var(--page);
        border: 1px solid var(--border);
        border-radius: 8px;
        font-family: ui-monospace, Menlo, monospace;
        font-size: 12px;
        color: var(--ink-2);
        white-space: pre-wrap;
        word-break: break-all;
      }
    </style>
  </head>
  <body>
