    <!-- 원본 JSON -->
    <details class="raw">
      <summary>원본 JSON 보기 (8개 엔드포인트)</summary>
      <div class="raw-grid">
        <div
          class="card"
          style="padding:0;overflow:hidden;"
          id="epList"
