const App = () => {
  const btnRef = useRef(null);
  const [count, setCount] = useState(0);
  const onClick = () => {
    setCount((count) => count + 1);
  };

  useEffect(() => {
    // 레거시 모드에서는 10, 11로 화면에 노출
    // 동시성 모드에서는 1, 11로 화면에 노출(1차 우선순위 높은거 실행, 2차 순차적으로 실행.)
    // [10_2, x+1_1]
    setTimeout(() => {
      setCount(count + 10);
    }, 2000);
    setTimeout(() => {
      btnRef.current.click();
    }, 2000);
  }, []);
  return (
    <>
      <h1>{count}</h1>
      <div
        onClick={onClick}
        ref={btnRef}
      >
        click1
      </div>
      {arr.map(() => (
        <div>{count}</div>
      ))}
    </>
  );
};



